typedef struct {
    Value *stack;
    Instr *code;
    uint64_t pc;
    uint64_t base;
    uint64_t top;
    int32_t status;
} Ctx;

static inline uint32_t get_A(uint32_t w) { return (w >> 7) & 255; }
static inline uint32_t get_B(uint32_t w) { return (w >> 16) & 255; }
static inline uint32_t get_C(uint32_t w) { return (w >> 24) & 255; }

