            uint32_t dst = ctx->base + get_A(w);
            uint32_t lhs_idx = ctx->base + get_B(w);
            uint32_t rhs_idx = ctx->base + get_C(w);
            Value lhs = ctx->stack[lhs_idx];
            Value rhs = ctx->stack[rhs_idx];
            if (lhs.tag == 8 && rhs.tag == 8) {
